    const initialTimeout = window.setTimeout(applyHighlight, 350);
    window.addEventListener("hashchange", applyHighlight);
    return () => {
      window.clearTimeout(initialTimeout);
      window.removeEventListener("hashchange", applyHighlight);
    };
