1	import React, { useState, useEffect } from "react";
2	import { motion } from "framer-motion";
3	import { formatBigNumber, formatDelta } from "../utils/format";
4	import {
5	  MONAD_STATS_URL,
6	  OPENCLAW_AGENT_STATS_URLS,
7	  readTokenScalar,
8	} from "../data/openclaw-sources";
9	
10	// Manifest produced by the centralized collector in project-assets.
11	// Lists every collected repo + its stats; the aggregate bar sums across all of them
12	// so new repos auto-roll into the headline numbers without a code change here.
13	const MANIFEST_URL = "https://raw.githubusercontent.com/Jason-Vaughan/project-assets/main/_collect-meta.json";
14	
15	/**
16	 * Builder stats bar — fetches stats from all projects and displays aggregated totals.
17	 */
18	export default function BuilderStats() {
19	  const [totals, setTotals] = useState(null);
20	  const [hoveredLabel, setHoveredLabel] = useState(null);
21	  // Local-inference token breakdown — Monad-1 publisher + every OpenClaw
22	  // agent that self-publishes. Used to add local tokens onto the AI Tokens
23	  // tile and to render a per-source breakdown in the tooltip.
24	  const [localTokens, setLocalTokens] = useState({ monad: 0, agents: [] });
25	
26	  useEffect(() => {
27	    // Fetch monad-stats + every OpenClaw agent in parallel. allSettled so
28	    // a single source being down doesn't tank the rest of the aggregation.
29	    Promise.allSettled([
30	      fetch(MONAD_STATS_URL, { cache: "no-store" }).then((r) => (r.ok ? r.json() : null)),
31	      ...OPENCLAW_AGENT_STATS_URLS.map((s) =>
32	        fetch(s.url, { cache: "no-store" }).then((r) => (r.ok ? r.json() : null)),
33	      ),
34	    ]).then((results) => {
35	      const monadTotal = results[0].status === "fulfilled" && results[0].value
36	        ? readTokenScalar(results[0].value?.tokens?.total)
37	        : 0;
38	      const agents = OPENCLAW_AGENT_STATS_URLS.map((s, i) => {
39	        const r = results[i + 1]; // offset by 1 (Monad was first)
40	        const total = r.status === "fulfilled" && r.value
41	          ? readTokenScalar(r.value?.tokens?.total)
42	          : 0;
43	        return { name: s.name, total };
44	      });
45	      setLocalTokens({ monad: monadTotal, agents });
46	    });
47	  }, []);
48	
49	  useEffect(() => {
50	    fetch(MANIFEST_URL, { cache: "no-store" })
51	      .then((r) => {
52	        if (!r.ok) {
53	          console.warn(`[BuilderStats] manifest fetch returned ${r.status}; bar hidden`);
54	          return null;
55	        }
56	        return r.json();
57	      })
58	      .then((manifest) => {
59	        if (!manifest?.projects) {
60	          if (manifest) console.warn("[BuilderStats] manifest has no `projects` key; bar hidden");
61	          return;
62	        }
63	
64	        const successful = Object.values(manifest.projects).filter((p) => p.ok && p.stats);
65	        if (successful.length === 0) {
66	          console.warn("[BuilderStats] manifest has zero successful projects; bar hidden");
67	          return;
68	        }
69	
70	        const totals = successful.reduce(
71	          (acc, p) => ({
72	            loc: acc.loc + (p.stats.loc || 0),
73	            tests: acc.tests + (p.stats.tests || 0),
74	            commits: acc.commits + (p.stats.commits || 0),
75	            projects: acc.projects + 1,
76	          }),
77	          { loc: 0, tests: 0, commits: 0, projects: 0 }
78	        );
79	
80	        totals.tokens = manifest.aggregateTokens?.total || 0;
81	        totals.fixes = manifest.aggregateFixes?.count || 0;
82	        totals.prs = manifest.aggregatePRs?.merged || 0;
83	        totals.refactored = manifest.aggregateRefactored?.count || 0;
84	        totals.authored = manifest.aggregateAuthored?.count || 0;
85	
86	        // Week-over-week deltas come pre-computed in the manifest (added by
87	        // the collector after PR-on-project-assets#TBD). Defaults to empty so
88	        // older manifests degrade gracefully (no badges render).
89	        totals.deltas = manifest.aggregateDeltas || null;
90	
91	        setTotals(totals);
92	      })
93	      .catch((err) => {
94	        console.warn("[BuilderStats] manifest fetch failed:", err.message);
95	      });
96	  }, []);
97	
98	  // Hide section if no stats loaded yet
99	  if (!totals) return null;
100	
101	  // `exact` = raw integer for the hover tooltip (precise value)
102	  // `delta` = signed change vs the same metric 7 days ago, or null if the
103	  //          manifest doesn't yet have aggregateDeltas (graceful degrade).
104	  const d = totals.deltas;
105	  const stats = [
106	    {
107	      label: "Lines of Code",
108	      value: formatBigNumber(totals.loc),
109	      exact: totals.loc,
110	      delta: d ? d.loc : null,
111	      color: "#38bdf8",
112	      description: "Current snapshot of source files across all tracked repos — what lives in the codebase right now. Counts hand-written source, markup, styles, docs, and config (JS/TS, Python, HTML, CSS, Markdown, and more) across every repo; generated and vendored files (lockfiles, build output, node_modules) are excluded. Different from lifetime-added, since refactoring removes lines as it adds new ones.",
113	    },
114	    {
115	      label: "Commits",
116	      value: formatBigNumber(totals.commits),
117	      exact: totals.commits,
118	      delta: d ? d.commits : null,
119	      color: "#a78bfa",
120	      description: "Total commits across all tracked repos, summed from `git rev-list HEAD` per repo. Includes both direct-to-main and squash-merged PRs.",
121	    },
122	    {
123	      label: "Tests Passing",
124	      value: formatBigNumber(totals.tests),
125	      exact: totals.tests,
126	      delta: d ? d.tests : null,
127	      color: "#34d399",
128	      description: "Sum of `it()` / `test()` calls across every test file (`*.test.*` / `*.spec.*`) in every repo. Counts assertions that exist in the codebase — not test runs.",
129	    },
130	    {
131	      label: "Projects Shipped",
132	      value: String(totals.projects),
133	      exact: totals.projects,
134	      delta: null, // headcount change is rare; not surfaced as a delta badge
135	      color: "#fbbf24",
136	      description: "Public + private repos in the live stats registry. Auto-discovered from GitHub, then filtered by `projects.yml` exclusions (archived experiments, scratch repos, asset-only repos).",
137	    },
138	  ];
139	
140	  // AI Tokens = cloud-provider tokens (centralized manifest) + Monad-1's own
141	  // tokens.total. Monad's publisher already counts every OpenClaw agent that
142	  // routes to it (LiteLLM + Ollama tee), so agents are NOT added separately —
143	  // that double-counted (see openclaw-sources.js). Headline signal: "total AI
144	  // work done, anywhere I run it."
145	  const cloudTokens = totals.tokens; // already from manifest.aggregateTokens.total
146	  const localAgentTotal = localTokens.agents.reduce((sum, a) => sum + a.total, 0);
147	  const localTotal = localTokens.monad + localAgentTotal;
148	  const allTokens = cloudTokens + localTotal;
149	
150	  if (allTokens > 0) {
151	    // Build a multi-line breakdown for the tooltip. Local inference is a single
152	    // "Monad-1" line: routed OpenClaw agents are already inside Monad's published
153	    // tokens.total, so localTotal is just Monad's own number (no agent sum). A
154	    // genuinely standalone rig — counted nowhere else — would get its own line.
155	    const breakdownLines = [];
156	    if (cloudTokens > 0) {
157	      breakdownLines.push(`Cloud providers: ${formatBigNumber(cloudTokens)}`);
158	    }
159	    if (localTotal > 0) {
160	      breakdownLines.push(`Monad-1 (local inference): ${formatBigNumber(localTotal)}`);
161	    }
162	
163	    stats.push({
164	      label: "AI Tokens",
165	      value: formatBigNumber(allTokens),
166	      exact: allTokens,
167	      delta: null,
168	      color: "#f472b6",
169	      description:
170	        "Lifetime tokens consumed across cloud providers (Anthropic, OpenAI, Cursor, Gemini, Copilot) plus local inference on Monad-1 and the OpenClaw fleet. Cloud totals refresh daily; local totals refresh every 15 min via each agent's self-published stats.",
171	      breakdown: breakdownLines.length > 1 ? breakdownLines : null,
172	    });
173	  }
174	
175	  // Only show Fixes Shipped once the manifest carries a non-zero aggregate
176	  if (totals.fixes > 0) {
177	    stats.push({
178	      label: "Fixes Shipped",
179	      value: formatBigNumber(totals.fixes),
180	      exact: totals.fixes,
181	      delta: d ? d.fixes : null,
