cd ~/code/project-assets; node --input-type=module -e '
import { execSync } from "node:child_process";
import fs from "node:fs";
const cur = JSON.parse(fs.readFileSync("_collect-meta.json","utf8"));
const oldSha = execSync("git log --before=\"7 days ago\" -n 1 --format=%H -- _collect-meta.json",{encoding:"utf8"}).trim();
const old = JSON.parse(execSync(`git show ${oldSha}:_collect-meta.json`,{encoding:"utf8"}));
const cnt = m => Object.values(m.projects||{}).filter(p=>p.ok&&p.stats).length;
const repoCount = cnt(cur), oldProjects = cnt(old);
const projectsDelta = repoCount - oldProjects;
const tokensDelta = (old.aggregateTokens && typeof old.aggregateTokens.total==="number" && cur.aggregateTokens && typeof cur.aggregateTokens.total==="number")
  ? cur.aggregateTokens.total - old.aggregateTokens.total : null;
console.log("oldSha:", oldSha.slice(0,8));
console.log("projects: now", repoCount, "was", oldProjects, "=> delta", projectsDelta);
console.log("tokens: now", cur.aggregateTokens?.total?.toLocaleString(), "was", old.aggregateTokens?.total?.toLocaleString(), "=> delta", tokensDelta?.toLocaleString());
'

