content.content:
1	/**
2	 * Format a positive integer with K/M/B suffix for display in stat tiles.
3	 * Negative inputs are not expected in this codebase (stats are counts) so they
4	 * fall through to toLocaleString without special handling.
5	 *
6	 * Precision rules (chosen to make small changes visible):
7	 *   - <  1K       → "N"        (raw toLocaleString)
8	 *   - 1K-100K     → "N.NK+"    (one decimal — surfaces hundreds-level moves)
9	 *   - 100K-1M     → "NK+"      (whole K — value already has 3 sig figs)
10	 *   - 1M+         → "N.NM+"    (one decimal)
11	 *   - 1B+         → "N.NNB+"   (two decimals — so M-scale additions to a
12	 *                                B-scale number are still visible. AI Tokens
13	 *                                at billions-scale gets hit hardest: adding
14	 *                                14M of local inference to 9.3B was invisible
15	 *                                at 1 decimal precision)
16	 *
17	 * @param {number} n
18	 * @returns {string}
19	 */
20	export function formatBigNumber(n) {
21	  if (n >= 1_000_000_000) return `${(n / 1_000_000_000).toFixed(2)}B+`;
22	  if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M+`;
23	  if (n >= 100_000) return `${Math.floor(n / 1000)}K+`;
24	  if (n >= 1_000) return `${(n / 1000).toFixed(1)}K+`;
25	  return n.toLocaleString();
26	}
27	
28	/**
29	 * Format a delta (signed) for display next to a stat tile.
30	 * Always shows the sign so positive numbers read as "+12" not "12".
31	 *
32	 * @param {number} d
33	 * @returns {string}
34	 */
